use actix_files::NamedFile;
use actix_web::{error, web, App, HttpRequest, HttpServer, Result};
use std::path::{Component, Path, PathBuf};

fn sanitize_filename(input: &str) -> Result<PathBuf> {
    if input.is_empty() {
        return Err(error::ErrorBadRequest("missing filename"));
    }

    let p = Path::new(input);

    if p.is_absolute() {
        return Err(error::ErrorBadRequest("invalid filename"));
    }

    let mut out = PathBuf::new();
    for c in p.components() {
        match c {
            Component::Normal(s) => out.push(s),
            Component::CurDir => {}
            _ => return Err(error::ErrorBadRequest("invalid filename")),
        }
    }

    if out.as_os_str().is_empty() {
        return Err(error::ErrorBadRequest("invalid filename"));
    }

    Ok(out)
}

async fn serve_upload(req: HttpRequest, path: web::Path<String>) -> Result<NamedFile> {
    let rel = sanitize_filename(&path.into_inner())?;
    let full = Path::new("uploads").join(rel);
    let file = NamedFile::open_async(full).await.map_err(error::ErrorNotFound)?;
    Ok(file.use_last_modified(true).prefer_utf8(true))
}

